func:
var c=parseFloat(msg.payload);
var l=flow.get('lastTemp');
if(l!=null&&Math.abs(c-l)>10){
  var a={payload:'['+new Date().toLocaleTimeString()+'] ANOMALY: Temp jumped '+Math.abs(c-l).toFixed(1)+'C ('+l+'>'+c+') — Possible spoofing!',topic:'ANOMALY'};
  flow.set('lastTemp',c);
  return[msg,a];
}
flow.set('lastTemp',c);
return[msg,null];

var c=parseFloat(msg.payload);
var l=flow.get('lastGasVal');
if(l!=null&&(c-l)>2000){
  var a={payload:'['+new Date().toLocaleTimeString()+'] ANOMALY: Gas jumped '+(c-l)+' ADC ('+l+'>'+c+') — Possible spoofing!',topic:'ANOMALY'};
  flow.set('lastGasVal',c);
  return[msg,a];
}
flow.set('lastGasVal',c);
return[msg,null];

var s=msg.payload;
if(s==='ALERT')msg.payload='<div style="background:#b71c1c;color:#fff;padding:12px;border-radius:6px;font-size:16px;font-weight:700;text-align:center;">⚠  GAS ALERT DETECTED  ⚠</div>';
else msg.payload='<div style="background:#1b5e20;color:#fff;padding:12px;border-radius:6px;font-size:16px;font-weight:700;text-align:center;">✓  GAS NORMAL</div>';
return msg;

var s=msg.payload;
var bg={'OK':'#1b5e20','LOW':'#e65100','CRITICAL':'#b71c1c','ERROR':'#424242'};
var label={'OK':'✓  Tank OK','LOW':'⚠  Water Low','CRITICAL':'🚨  CRITICAL — Refill Now','ERROR':'❌  Sensor Error'};
msg.payload='<div style="background:'+(bg[s]||'#333')+';color:#fff;padding:12px;border-radius:6px;font-size:16px;font-weight:700;text-align:center;">'+(label[s]||s)+'</div>';
return msg;

var s=msg.payload;
var bg={'ONLINE':'#1b5e20','OFFLINE':'#b71c1c'};
var label={'ONLINE':'✓  ARM Node ONLINE — Heartbeat Active','OFFLINE':'❌  ARM Node OFFLINE'};
msg.payload='<div style="background:'+(bg[s]||'#37474f')+';color:#fff;padding:12px;border-radius:6px;font-size:16px;font-weight:700;text-align:center;">'+(label[s]||'ARM: '+s)+'</div>';
return msg;

var now=new Date().toLocaleTimeString();
msg.payload='['+now+'] 🚨 PANIC BUTTON — STM32 ARM Node';
msg.topic='ARM_PANIC';
return msg;

msg.topic='PANIC ALERT — Smart Home IoT';
msg.payload='PANIC BUTTON PRESSED on STM32 ARM Node!

Time: '+new Date().toLocaleString()+'

Immediate attention required!';
return msg;

var t=msg.topic;
if(t==='capstone/esp32/led'||t==='capstone/pico2/led'||t==='arm/led'||t==='capstone/esp32/buzzer'){
  return msg;
}
return null;

var a=flow.get('anomalyLog')||[];
a.unshift({Time:new Date().toLocaleTimeString(),Type:'ANOMALY',Detail:msg.payload});
if(a.length>20)a=a.slice(0,20);
flow.set('anomalyLog',a);
msg.payload=a;
return msg;

var now=new Date().toLocaleTimeString();
var labels={'GAS_DETECTED':'💨 Gas Detected','HIGH_TEMP':'🔥 High Temperature','NORMAL':'✅ Normal','MANUAL_ALERT':'🚨 Manual Alert'};
var key=msg.payload;
msg.payload='['+now+'] '+(labels[key]||key);
msg.topic=key;
return msg;

var now=new Date().toLocaleTimeString();
var info=msg.payload.toString();
var known=['ESP32','Pico','nodered','testuser','NodeRED'];
if(!known.some(function(c){return info.indexOf(c)>=0;})){
  msg.payload='['+now+'] 🔒 SECURITY: Unknown client — '+info;
  msg.topic='SECURITY';
  return msg;
}
return null;

var alerts=flow.get('alertLog')||[];
alerts.unshift({Time:new Date().toLocaleTimeString(),Alert:msg.payload});
if(alerts.length>20)alerts=alerts.slice(0,20);
flow.set('alertLog',alerts);
msg.payload=alerts;
return msg;

var history=flow.get('sensorHistory')||[];
var row={
  Time:new Date().toLocaleTimeString(),
  Temp:String(msg.payload)+'C',
  Humidity:String(flow.get('hum')||'--')+'%',
  Gas:String(flow.get('gas')||'--'),
  Water:String(flow.get('water')||'--')+'%'
};
history.unshift(row);
if(history.length>20)history=history.slice(0,20);
flow.set('sensorHistory',history);
msg.payload=history;
return msg;

msg.topic = "ANOMALY ALERT — Smart Home IoT";
msg.payload = "ANOMALY DETECTED on Smart Home System!

Time: " + new Date().toLocaleString() + "

Detail: " + msg.payload + "

Check your dashboard immediately.";
return msg;
